-- Bump every challenge to 10 questions (tier_order 0-9). The table's CHECK
-- constraint only allowed 0-2, so widen it first (found dynamically since
-- inline CHECK constraint names aren't guaranteed across environments).
DO $$
DECLARE r RECORD;
BEGIN
  FOR r IN
    SELECT conname FROM pg_constraint
    WHERE conrelid = 'public.questions'::regclass
      AND pg_get_constraintdef(oid) ILIKE '%tier_order%'
  LOOP
    EXECUTE format('ALTER TABLE public.questions DROP CONSTRAINT %I', r.conname);
  END LOOP;
END $$;
ALTER TABLE public.questions ADD CONSTRAINT questions_tier_order_check CHECK (tier_order BETWEEN 0 AND 9);

-- ============================================================
-- Top up the 8 existing challenges from 3 to 10 questions each
-- (tier_order 3-9), continuing each case's diagnostic narrative
-- into repair verification, relearn procedures, and comeback
-- prevention rather than just padding difficulty.
