INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',7,'A different Camry arrives with an identical complaint and P0171. A tech skips live data and replaces the MAF immediately based on the last job. Root cause turns out to be a cracked intake boot. What principle was violated?','["None — MAF is always the fix for P0171","Diagnose using data before replacing parts, rather than pattern-matching to a prior unrelated repair","The tech should have checked spark plugs instead","The customer should have specified the exact cause"]'::jsonb,1,'Every P0171 needs its own data-driven diagnosis — the cause varies vehicle to vehicle.' FROM public.challenges WHERE slug='p0171-lean-bank1' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',8,'On the intake boot job, what''s the correct way to verify the repair beyond just clearing codes?','["Smoke test the repaired boot under vacuum, confirm trims normalize across idle/cruise/WOT, and complete a drive cycle","Clear codes and hand back the keys immediately","Only check for smoke at idle","Replace the O2 sensor regardless"]'::jsonb,0,'A full verification confirms both the physical repair and that the ECM has settled to normal trims.' FROM public.challenges WHERE slug='p0171-lean-bank1' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',9,'Overall, what''s the correct diagnostic sequence for any P0171 lean code, in order?','["Replace MAF, then O2 sensor, then check for leaks","Confirm the code with live data, interpret the trim pattern to localize the leak, smoke test to pinpoint it, repair, then verify with a drive cycle","Replace whichever sensor is cheapest first","Reflash the ECM before doing anything else"]'::jsonb,1,'Data first, then localization, then repair, then verification — the general lean-code methodology.' FROM public.challenges WHERE slug='p0171-lean-bank1' ON CONFLICT DO NOTHING;

