SELECT id,'Hard',6,'Battery load test shows 78% of rated CCA. Correct call?','["It''s fine, leave it","Recommend replacement — a marginal battery combined with any remaining system resistance increases risk of a repeat no-crank complaint","Charge it once and reinstall, no further action","The battery is unrelated to the starting circuit"]'::jsonb,1,'A marginal battery is itself a latent cause of recurring starting complaints, even after wiring is fixed.' FROM public.challenges WHERE slug='voltage-drop-no-crank' ON CONFLICT DO NOTHING;
