SELECT id,'Hard',7,'What''s the best way to explain this repair to the customer, given two separate faults were found?','["''We fixed it, it works now''","Explain both faults found, the data supporting each, and the battery test result showing a third contributing factor, tying it to why symptoms can recur without full diagnosis","No explanation needed, just bill for parts","Blame the previous shop only"]'::jsonb,1,'Transparent, data-backed explanations build trust and justify diagnostic time.' FROM public.challenges WHERE slug='voltage-drop-no-crank' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
