INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',9,'What''s the correct generalized diagnostic sequence for any slow-crank/no-crank complaint with good battery voltage at rest?','["Replace the starter immediately","Load test the battery, voltage-drop test the full positive and ground paths under cranking load, repair the highest-resistance points, and re-verify with repeated cold-crank cycles","Only check the ignition switch","Replace the PCM"]'::jsonb,1,'Static voltage checks miss under-load resistance faults entirely — always test under cranking load.' FROM public.challenges WHERE slug='voltage-drop-no-crank' ON CONFLICT DO NOTHING;

