INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',6,'The battery is 4 years old and was subjected to months of marginal charging before repair. What should be checked/recommended?','["Nothing, the battery is fine automatically","Load test the battery — prolonged undercharging can shorten battery life and it may need replacement even though it currently starts the car","Replace the battery regardless of test results, always","Ignore the battery, only the alternator matters"]'::jsonb,1,'A history of marginal charging is a real reason to specifically test the battery, not assume it''s fine.' FROM public.challenges WHERE slug='alternator-charging' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',7,'Battery load tests at 65% of rated capacity. What''s the correct recommendation and reasoning to the customer?','["Say nothing, let them find out later","Recommend battery replacement now, explaining the marginal charging period likely degraded it and a weak battery risks a repeat complaint","Tell them to just keep jump-starting it","Recommend replacing the alternator again"]'::jsonb,1,'Explaining the causal link between the old fault and the battery''s condition justifies the recommendation.' FROM public.challenges WHERE slug='alternator-charging' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',8,'What data points should be documented on the RO to fully support this repair?','["''Replaced alternator''","Before/after voltage, load amps, cable drop, AC ripple readings, plus battery load test result and reasoning for the replacement recommendation","No documentation needed","Just the part numbers"]'::jsonb,1,'Full before/after data is what makes the diagnosis and recommendation defensible.' FROM public.challenges WHERE slug='alternator-charging' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',9,'What''s the correct generalized diagnostic sequence for a charging system complaint (battery light, weak charge)?','["Replace the alternator immediately","Test charging voltage at idle and under load, voltage-drop test the B+ and ground cables, check AC ripple for diode issues, and load test the battery","Only check the serpentine belt","Only replace the battery"]'::jsonb,1,'Alternator, cabling, and battery can each independently contribute — all should be verified.' FROM public.challenges WHERE slug='alternator-charging' ON CONFLICT DO NOTHING;

-- can-bus-u-codes-ram (Ram 2500 6.7 Cummins, Diesel/Network)
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',3,'The TCM is checked for a stored ''lost communication'' timestamp. It aligns exactly with the jump-start event. What does this suggest?','["The TCM is permanently damaged","The voltage spike/drop during the jump-start likely caused a momentary communication dropout the TCM latched as a fault, not an ongoing physical problem","The CAN bus wiring is still faulty","The ECM needs replacement"]'::jsonb,1,'A timestamp matching a known voltage event strongly suggests a latched historical fault, not a live one.' FROM public.challenges WHERE slug='can-bus-u-codes-ram' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',4,'Correct procedure to clear a latched communication fault after confirming the physical bus is healthy?','["Replace the TCM regardless","Clear the DTC, cycle the key, and run a drive cycle to confirm the code doesn''t return now that the terminator is fixed","Disconnect the battery for a week","Reflash all modules"]'::jsonb,1,'Clearing and re-verifying confirms whether the fault was truly latched versus still active.' FROM public.challenges WHERE slug='can-bus-u-codes-ram' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',5,'After the drive cycle, U0100 does not return and all modules communicate normally. What final check confirms the whole vehicle network is healthy?','["Nothing further needed","A full system scan across all modules to check for any other stored or pending U-codes indicating a broader issue","Only check the radio","Only check modules that had power during the jump-start"]'::jsonb,1,'A full scan catches issues in modules that weren''t the original focus of the complaint.' FROM public.challenges WHERE slug='can-bus-u-codes-ram' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',6,'Full scan comes back clean. What advice prevents recurrence on future jump-starts?','["None needed","Use proper jump-starting procedure (correct polarity, engine off during connection, or a jump box with voltage-spike protection) to avoid transients that can cause module faults","Always disconnect the battery before any jump-start","Jump-starts never cause electronic issues"]'::jsonb,1,'Correct jump-start technique reduces the voltage transients that caused this exact fault.' FROM public.challenges WHERE slug='can-bus-u-codes-ram' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',7,'If the terminating resistor had NOT been the issue (normal ~60 ohms from the start), what would be the next step for multiple U-codes?','["Assume it''s unfixable and replace the whole harness","Check CAN-H and CAN-L for shorts to power/ground and opens using a scope or DMM at multiple points, since normal resistance rules out a terminator but not a partial short","Replace all modules one by one","Ignore the codes if the truck still runs"]'::jsonb,1,'Normal bus resistance narrows the fault to wiring integrity issues rather than a terminator.' FROM public.challenges WHERE slug='can-bus-u-codes-ram' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',8,'What RO documentation best explains this repair for warranty/comeback purposes?','["''Fixed electrical issue''","Root cause (open CAN terminator from a pushed-back BCM pin), resistance readings before/after, and confirmation the U0100 code was a latched jump-start event that cleared after physical repair and drive cycle","''Cleared codes, no issue found''","No documentation, just close the RO"]'::jsonb,1,'This level of detail explains both the physical fix and the residual code behavior.' FROM public.challenges WHERE slug='can-bus-u-codes-ram' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',9,'What''s the correct generalized diagnostic sequence for multiple U-codes on a network bus?','["Replace the module with the most codes first","Rule out power/ground first, check bus resistance for terminator faults, scope for shorts/opens if resistance is normal, distinguish latched from active faults, repair, then confirm with a drive cycle and full scan","Always replace the ECM","Ignore U-codes if the vehicle starts"]'::jsonb,1,'This sequence separates power issues, physical bus faults, and latched history from each other.' FROM public.challenges WHERE slug='can-bus-u-codes-ram' ON CONFLICT DO NOTHING;

