INSERT INTO public.challenges (slug,title,type,specialty,xp_reward,description,tags) VALUES
  ('tcc-shudder-diagnosis','TCC Shudder — Torque Converter Clutch Diagnosis','component','Automotive',130,'2015 Toyota Camry 2.5L, 6-speed automatic. Vibration/shudder felt through the seat between 45-55 mph under light throttle, most noticeable when warm.',ARRAY['Transmission','TCC','Torque Converter']),
  ('p242f-dpf-regen-failure','P242F — DPF Regeneration Failure, High Soot Load','dtc','Diesel',140,'2017 Ram 3500 6.7 Cummins. DPF lamp on, reduced power mode, P242F stored. Highway driving has dropped off in favor of mostly short city trips.',ARRAY['DPF','Emissions','Regen','Cummins']),
  ('ro-awd-vibration-comeback','Repair Order — AWD Vibration Comeback Diagnosis','ro','Automotive',120,'2019 Subaru Outback AWD. Another shop replaced two tires for a highway-speed vibration; it returned within a week. Back for a proper root-cause diagnosis.',ARRAY['AWD','Driveline','Repair Order','Comeback'])
ON CONFLICT (slug) DO NOTHING;

INSERT INTO public.challenge_domains (challenge_id,domain) SELECT id,'Drivetrain'::public.skill_domain FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;
INSERT INTO public.challenge_domains (challenge_id,domain) SELECT id,'Emissions'::public.skill_domain FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;
