-- tcc-shudder-diagnosis
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Easy',0,'TCC shudder that appears only when warm, under light cruise load, most closely resembles which condition?','["A wheel balance issue","Torque converter clutch engagement/slip shudder — a classic symptom of TCC apply-related friction or fluid issues","A bad spark plug","Low tire pressure"]'::jsonb,1,'Speed and load-specific shudder when warm is textbook TCC apply shudder.' FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Easy',1,'What''s the first non-invasive check before suspecting internal transmission wear?','["Tear down the transmission","Check transmission fluid level, condition, and confirm the correct fluid type/spec was used in the last service","Replace the torque converter immediately","Replace the engine mounts"]'::jsonb,1,'Fluid condition and correct spec is the cheapest, fastest first check.' FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Easy',2,'Fluid is the correct type and level is right, but has a slightly burnt smell and darker color than normal. What does this suggest?','["Nothing of concern","Possible friction material degradation or overheating history, consistent with TCC clutch wear","The engine oil is contaminated","The coolant is low"]'::jsonb,1,'Burnt-smelling, dark ATF is a common indicator of clutch material breakdown or heat history.' FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',3,'Scan tool live data during a test drive shows TCC slip speed of 180 RPM sustained at cruise (spec: near 0 RPM once locked). What does this confirm?','["The TCC is not fully locking/engaging, causing the shudder — consistent with worn friction material or a solenoid issue","The engine is misfiring","The wheel speed sensors are miscalibrated","This is completely normal"]'::jsonb,0,'Sustained slip well above spec directly confirms the TCC isn''t achieving full lockup.' FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',4,'TCC apply pressure is checked and reads low compared to spec at the commanded duty cycle. What are the two most likely culprits to investigate next?','["Spark plugs and ignition coils","TCC solenoid performance and valve body wear/contamination at the TCC regulator circuit","Wheel bearings and CV joints","Alternator and battery"]'::jsonb,1,'Low apply pressure at the correct duty cycle points to the solenoid or the valve body circuit feeding it.' FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',5,'TCC solenoid resistance tests within spec, but the valve body has visible varnish/sludge in the TCC circuit passages. Correct next step?','["Replace the engine","Service or replace the valve body (or have it rebuilt) and perform a full fluid and filter change","Ignore it and just top off fluid","Replace the torque converter only, valve body unrelated"]'::jsonb,1,'A good solenoid with a fouled valve body still needs the valve body addressed.' FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',6,'After valve body service and fluid/filter change, shudder is much reduced but a faint shudder remains only right at initial TCC lock-up. What does this suggest?','["The repair failed completely","The torque converter''s internal clutch friction material itself may be worn/glazed, requiring converter replacement rather than just valve body service","Wheel alignment is off","The issue is unrelated and pre-existing"]'::jsonb,1,'A remaining lock-up-only shudder after fixing the hydraulic circuit points to the friction material itself.' FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',7,'Torque converter is replaced along with a full fluid exchange. What must be done regarding TCM adaptive values before the final road test?','["Nothing, it adapts automatically with no reset needed","Reset/clear the transmission adaptive learning values via scan tool so the TCM relearns shift and TCC apply pressures for the new converter, then run a relearn drive cycle","Reflash the ECM only","Disconnect the battery for a month"]'::jsonb,1,'Old adaptive values tuned for the worn converter would misapply pressure on the new one.' FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',8,'Post-repair test drive: TCC slip speed now under 15 RPM at cruise, no shudder across multiple warm-up cycles. What final step should close out this repair?','["None, it''s done","Confirm no shudder across varied speeds/loads while warm, verify no new codes stored, and document baseline slip speed for future reference","Just check the fluid level one more time","Replace the transmission mount as well, unrelated but ''just in case''"]'::jsonb,1,'Broad condition testing plus a documented baseline gives a clean, defensible close-out.' FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',9,'What''s the correct generalized diagnostic sequence for a TCC shudder complaint?','["Replace the transmission immediately","Verify fluid condition/type first, confirm TCC slip via live data, check apply pressure and solenoid/valve body health, address root cause in order of invasiveness, then relearn adaptive values and verify with a drive cycle","Always replace the torque converter first regardless of data","Ignore shudder complaints since they''re subjective"]'::jsonb,1,'Least-invasive-first ordering avoids unnecessary converter replacement when a valve body service would fix it.' FROM public.challenges WHERE slug='tcc-shudder-diagnosis' ON CONFLICT DO NOTHING;

-- p242f-dpf-regen-failure
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Easy',0,'What does P242F (DPF soot load too high) most directly indicate?','["A fuel pressure fault","The diesel particulate filter has accumulated more soot than the system can safely manage without intervention","A transmission fault","A coolant leak"]'::jsonb,1,'The code is a direct soot-load threshold warning, not a component failure code by itself.' FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Easy',1,'The customer''s driving pattern (mostly short city trips) is relevant because:','["It''s unrelated to DPF health","Short trips often don''t get the exhaust hot enough for long enough to complete passive/active regeneration, letting soot accumulate over time","Short trips only affect fuel economy","Short trips damage the turbocharger only"]'::jsonb,1,'Regen requires sustained exhaust temperature that short city trips rarely reach.' FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Easy',2,'What should be checked with the scan tool before attempting any regen?','["Nothing, just start a forced regen immediately","Current soot load percentage and DPF differential pressure readings to confirm how severe the accumulation is","Tire pressure sensors","Radio settings"]'::jsonb,1,'Knowing the severity first determines whether a forced regen is even appropriate.' FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',3,'Soot load reads 85% and differential pressure is elevated at idle. What''s the appropriate next step?','["Replace the DPF immediately without attempting regen","Attempt a scan-tool-commanded stationary forced regeneration, since soot load, while high, may still be low enough to burn off with an assisted regen","Tell the customer nothing can be done","Disconnect the DPF and drive without it"]'::jsonb,1,'A forced regen is the standard first attempt before considering filter replacement.' FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',4,'During the forced regen, exhaust gas temperature fails to reach target. What are the likely contributing components to check?','["Wheel bearings","Post-injection fuel delivery for regen, EGT sensors, and the DOC upstream of the DPF, since any of these can prevent reaching regen temperature","Battery terminals","Cabin air filter"]'::jsonb,1,'Any of these three can independently prevent the exhaust from reaching regen temperature.' FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',5,'EGT sensor readings before/after the DOC show a smaller-than-expected temperature rise across it. What does this suggest?','["The DOC is functioning perfectly","The DOC may be contaminated or degraded, not generating enough exothermic reaction heat to support DPF regen","The DPF itself is the only problem","This is a normal reading"]'::jsonb,1,'A weak temperature rise across the DOC directly indicates reduced catalytic activity.' FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',6,'DOC is found coated/contaminated. What must be checked as a root cause before simply replacing it?','["Nothing, just replace the DOC and move on","Check for excessive oil consumption/burning or fuel dilution issues that could be contaminating the DOC and would recontaminate a new one if unaddressed","Only check the tire tread","Replace the transmission"]'::jsonb,1,'Replacing a contaminated DOC without fixing the contamination source just repeats the failure.' FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',7,'Oil consumption is confirmed above normal, with the crankcase filter contributing extra oil vapor into the intake. What repair addresses the root cause?','["Replace the DOC and DPF only, ignore the oil issue","Address the oil consumption source (e.g., replace crankcase ventilation filter/valve, inspect for related wear) in addition to DOC/DPF service","Just top off oil more frequently and ignore the smoke","Reflash the ECM only"]'::jsonb,1,'Leaving the oil source unaddressed guarantees the new emissions parts get recontaminated.' FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',8,'After DOC/DPF service and addressing the oil consumption source, what verification sequence confirms the repair?','["None, just clear codes and hand back the keys","Perform a forced regen to confirm normal EGT rise across the DOC and successful soot burn-off, verify soot load drops to baseline, clear codes, and road test to confirm no return of reduced power mode","Only check DPF differential pressure once","Skip the regen since parts are new"]'::jsonb,1,'A full forced-regen verification confirms the whole chain is working, not just that parts were swapped.' FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',9,'What advice should be given to the customer to prevent recurrence given their short-trip driving pattern?','["None needed, the repair is permanent regardless of driving habits","Periodically take longer highway trips (or manually initiate stationary regens per OEM guidance) since consistently short trips caused the original soot buildup","Avoid highway driving entirely","Remove the DPF permanently"]'::jsonb,1,'Their driving pattern was the original root cause, so it needs to change or be compensated for.' FROM public.challenges WHERE slug='p242f-dpf-regen-failure' ON CONFLICT DO NOTHING;

-- ro-awd-vibration-comeback
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Easy',0,'Given the vibration returned quickly after a tire replacement, what''s the correct first step before doing any new repair?','["Immediately replace the other two tires as well","Review the previous shop''s notes if available and gather detailed symptom info from the customer before assuming the same root cause","Assume the previous shop was wrong about everything","Skip straight to replacing the driveshaft"]'::jsonb,1,'Gathering context first avoids repeating a guess that already failed once.' FROM public.challenges WHERE slug='ro-awd-vibration-comeback' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Easy',1,'Customer says the vibration is speed-related, increasing with speed, regardless of braking or turning. What does this pattern suggest?','["A brake issue","A rotating component out of balance or worn, such as a tire/wheel, driveshaft, or wheel bearing","A steering rack issue only","An engine mount issue"]'::jsonb,1,'Speed-proportional vibration independent of braking/turning points to a rotating component.' FROM public.challenges WHERE slug='ro-awd-vibration-comeback' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Easy',2,'What''s the correct first diagnostic test for a speed-related vibration on an AWD vehicle?','["Replace the transmission","A road test to confirm and characterize the vibration, then a tire/wheel balance and runout check, since that''s the least invasive and most common cause","Replace the AWD transfer case immediately","Replace all four tires without testing"]'::jsonb,1,'Start with the least invasive, most statistically common cause before moving to the driveline.' FROM public.challenges WHERE slug='ro-awd-vibration-comeback' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',3,'New tires balance out fine with no excessive runout. Vibration is still present at highway speed. What''s the next logical component to check on this AWD vehicle?','["The radio antenna","The driveshaft and center support bearing for wear, runout, or damage, since AWD vehicles have a rear driveshaft that''s a common vibration source often overlooked when focusing only on tires","The windshield wipers","The cabin air filter"]'::jsonb,1,'With tires ruled out, the driveshaft is the next most common speed-related vibration source on AWD.' FROM public.challenges WHERE slug='ro-awd-vibration-comeback' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',4,'Driveshaft inspected — one of the two U-joints shows play when checked by hand with the shaft supported. What does this indicate?','["Normal wear, no action needed","A worn U-joint is a likely contributor to the vibration and should be replaced (or the driveshaft assembly, depending on design)","The transmission needs replacement","This is unrelated to vibration complaints"]'::jsonb,1,'Detectable play in a U-joint under no load is already beyond normal wear tolerance.' FROM public.challenges WHERE slug='ro-awd-vibration-comeback' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Medium',5,'Why is it important to check the U-joint with the shaft supported and under no load, rather than just looking at it?','["It''s not important, visual is enough","Play/looseness in a U-joint can be subtle and only detectable by hand-checking for movement, since visual inspection alone often misses early-stage wear that still causes vibration at speed","Only a spin balance machine can detect U-joint wear","U-joints never wear out"]'::jsonb,1,'Early-stage U-joint wear is a tactile finding, not always a visible one.' FROM public.challenges WHERE slug='ro-awd-vibration-comeback' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',6,'After replacing the driveshaft/U-joint, what should be checked given this is an AWD vehicle with a center differential/transfer case in the driveline?','["Nothing else, the repair is complete","Confirm all driveline components (differential fluid, transfer case) are in good condition and the new driveshaft is properly torqued and phased correctly, since improper installation can introduce a new vibration","Replace the transfer case regardless","Only check tire pressure again"]'::jsonb,1,'Incorrect driveshaft phasing is a common installation error that reintroduces vibration.' FROM public.challenges WHERE slug='ro-awd-vibration-comeback' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',7,'Test drive after the repair shows the original vibration is gone. What should be documented on the RO to distinguish this from the previous shop''s incomplete repair?','["''Fixed vibration''","Root cause identified (worn U-joint on rear driveshaft), confirmed via hand-check with shaft supported, distinct from the tire imbalance addressed previously, plus post-repair road test confirmation","Nothing, just close the RO","Blame the customer for not returning sooner"]'::jsonb,1,'A specific root cause note explains why the first repair attempt didn''t resolve the complaint.' FROM public.challenges WHERE slug='ro-awd-vibration-comeback' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',8,'The customer asks why the first shop''s tire replacement didn''t fix it. What''s the most professional and accurate explanation?','["''They were incompetent''","Tire imbalance can also cause speed-related vibration, so it was a reasonable first check, but there were two contributing factors here and only the tire was addressed — a full driveline inspection was needed to find the second cause","''It''s your fault for driving on bad tires''","Avoid the question entirely"]'::jsonb,1,'Acknowledging the first check was reasonable while explaining the missed second cause is both accurate and professional.' FROM public.challenges WHERE slug='ro-awd-vibration-comeback' ON CONFLICT DO NOTHING;
INSERT INTO public.questions (challenge_id,difficulty,tier_order,question_text,options,correct_index,explanation)
SELECT id,'Hard',9,'What''s the correct generalized diagnostic sequence for a comeback vibration complaint after a previous repair didn''t resolve it?','["Assume the same fix will work if repeated","Re-verify the complaint firsthand, work from least to most invasive, check for multiple contributing causes rather than stopping at the first finding, repair, and document clearly to explain the difference from the prior attempt","Replace the entire drivetrain to be safe","Tell the customer nothing can be done"]'::jsonb,1,'Comebacks often mean a second, unaddressed cause exists alongside the first — keep looking, don''t stop at one finding.' FROM public.challenges WHERE slug='ro-awd-vibration-comeback' ON CONFLICT DO NOTHING;
